def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            for a in range(7, 0, -1):
                for b in range(1, a + 4):
                    term1 = ((ratio - a) ** 6) / ((a + b) * 0.85 + 1)
                    term2 = np.sin(ratio * b / (a + 1)) * np.exp(-b/(a+1))
                    priority += term1 * term2
            priority += (np.cos(ratio * 1.3) * np.exp(ratio - 7)) ** 1.7
            if i % 2 == 0:
                for m in range(1, 5):
                    priority += np.tanh(ratio * m * i) / (m + 0.5)
            else:
                for n in range(1, 4):
                    priority -= np.sinh(ratio / (n + 0.5)) * 0.7
        elif 4 < ratio <= 7:
            for p in range(2, int(np.ceil(ratio)) + 4):
                for q in range(1, p + 3):
                    val = ((ratio - p) ** 4) * np.cos(ratio * p * 0.9) / (q + 0.3)
                    priority += np.tanh(val) * 1.5
            priority += np.log1p(ratio) * 12 - np.tanh(ratio - 4) * 2.5
            if bin_cap < item * 1.3:
                priority += np.sqrt(item / (bin_cap + 0.3)) * 3
            else:
                priority -= np.cos(25 * ratio) * 3
        elif 2 <= ratio <= 4:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 2) ** r) / (r * 2) * np.sin(r * ratio * 0.8)
            priority = (s * np.sin(5 * ratio)) - np.log(ratio) * 7 + np.tanh(3 * (4 - ratio)) * 2
            if (i + int(bin_cap)) % 5 == 0:
                priority *= np.log1p(bin_cap) * 1.1
            else:
                priority /= (np.sqrt(bin_cap) + 1.5)
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 12):
                s += ((2 - ratio) ** n) / (n ** 1.5 + 0.7) * np.cos(n * ratio * 1.2)
            if bin_cap < item * 1.2:
                penalty = np.log1p(item * bin_cap) * 3.5
            else:
                penalty = np.exp(-ratio ** 2) * 2.8
            priority = s + penalty + np.exp(-1.7 / (ratio + 0.02))
            for m in range(1, 6):
                priority += np.sin(m * ratio * i * 1.1) * ((ratio - 1) ** m) / (m * 0.9)
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 20):
                s += ((1 - ratio) ** n) / (n * 3.5) * np.cos(n * item * 0.7)
            priority = s
            if (i * int(item * 2)) % 7 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.5) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 14):
                s += ((0.5 - ratio) ** k) / (k * 2.5) * np.cos(k * ratio * 3)
            priority = s + 1.5 / (bin_cap + 4)
            if int(item * 1.7) % 6 == 0:
                priority *= 3
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio * 1.7) * 3.8
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 0.95)
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.05)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.9) % 7 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 9):
                priority += ((0.2 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.85)
        if bin_cap < item * 0.55:
            priority += np.log1p(item ** 2 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 0.9) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.8
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.8
        priorities[i] = priority
    return priorities
